@namespace sv_a26a23e0998644a6b7638ac048aebd54.Components.JobApplication

<nav aria-label="Application steps" class="mb-4">
    <div class="d-flex justify-content-between position-relative">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i + 1;
            var isCompleted = step < CurrentStep;
            var isCurrent = step == CurrentStep;
            var isFuture = step > CurrentStep;

            <div class="text-center flex-fill" style="z-index: 1;">
                <button class="btn rounded-circle d-inline-flex align-items-center justify-content-center @StepClass(step)"
                        style="width: 40px; height: 40px; font-size: 0.85rem;"
                        disabled="@isFuture"
                        @onclick="() => OnStepClicked(step)">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        @step
                    }
                </button>
                <div class="mt-1 small @(isCurrent ? "fw-bold" : isFuture ? "text-muted" : "")">
                    @StepNames[i]
                </div>
            </div>
        }
    </div>
</nav>

@code {
    private static readonly string[] StepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnNavigateToStep { get; set; }

    private string StepClass(int step)
    {
        if (step < CurrentStep) return "btn-success text-white";
        if (step == CurrentStep) return "btn-primary text-white";
        return "btn-outline-secondary";
    }

    private async Task OnStepClicked(int step)
    {
        if (step < CurrentStep)
        {
            await OnNavigateToStep.InvokeAsync(step);
        }
    }
}

@namespace sv_a26a23e0998644a6b7638ac048aebd54.Components.JobApplication

<h4 class="mb-3">Personal Information</h4>

<div class="mb-3">
    <label for="fullName" class="form-label">Full Name <span class="text-danger">*</span></label>
    <input id="fullName" class="form-control @(FieldError("FullName"))" @bind="FullName" />
    @if (HasError("FullName")) { <div class="invalid-feedback d-block">Full name is required.</div> }
</div>

<div class="mb-3">
    <label for="email" class="form-label">Email <span class="text-danger">*</span></label>
    <input id="email" type="email" class="form-control @(FieldError("Email"))" @bind="Email" />
    @if (HasError("Email")) { <div class="invalid-feedback d-block">@_errors["Email"]</div> }
</div>

<div class="mb-3">
    <label for="phone" class="form-label">Phone <span class="text-danger">*</span></label>
    <input id="phone" type="tel" class="form-control @(FieldError("Phone"))" @bind="Phone" />
    @if (HasError("Phone")) { <div class="invalid-feedback d-block">Phone is required.</div> }
</div>

<div class="mb-3">
    <label for="address" class="form-label">Address <span class="text-danger">*</span></label>
    <textarea id="address" class="form-control @(FieldError("Address"))" @bind="Address" rows="2"></textarea>
    @if (HasError("Address")) { <div class="invalid-feedback d-block">Address is required.</div> }
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@_validating">
        @if (_validating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public EventCallback<string> FullNameChanged { get; set; }
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public EventCallback<string> EmailChanged { get; set; }
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public EventCallback<string> PhoneChanged { get; set; }
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public EventCallback<string> AddressChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }

    private Dictionary<string, string> _errors = new();
    private bool _validating;

    private bool HasError(string field) => _errors.ContainsKey(field);
    private string FieldError(string field) => HasError(field) ? "is-invalid" : "";

    private async Task HandleNext()
    {
        _errors.Clear();

        if (string.IsNullOrWhiteSpace(FullName)) _errors["FullName"] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(Email)) _errors["Email"] = "Email is required.";
