+    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }
+
+    private Dictionary<string, string> _errors = new();
+    private bool _validating;
+
+    private bool HasError(string field) => _errors.ContainsKey(field);
+    private string FieldError(string field) => HasError(field) ? "is-invalid" : "";
+
+    private async Task HandleNext()
+    {
+        _errors.Clear();
+
+        if (string.IsNullOrWhiteSpace(FullName)) _errors["FullName"] = "Full name is required.";
+        if (string.IsNullOrWhiteSpace(Email)) _errors["Email"] = "Email is required.";
+        if (string.IsNullOrWhiteSpace(Phone)) _errors["Phone"] = "Phone is required.";
+        if (string.IsNullOrWhiteSpace(Address)) _errors["Address"] = "Address is required.";
+
+        if (_errors.Count > 0) return;
+
+        _validating = true;
+        try
+        {
+            if (ValidateEmail is not null)
+            {
+                var isValid = await ValidateEmail(Email);
+                if (!isValid)
+                {
+                    _errors["Email"] = "Please enter a valid email address.";
+                    return;
+                }
+            }
+
+            await FullNameChanged.InvokeAsync(FullName);
+            await EmailChanged.InvokeAsync(Email);
+            await PhoneChanged.InvokeAsync(Phone);
+            await AddressChanged.InvokeAsync(Address);
+            await OnNext.InvokeAsync();
+        }
+        finally
+        {
+            _validating = false;
+        }
+    }
+}
