@namespace sv_a26a23e0998644a6b7638ac048aebd54.Components.JobApplication

<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    var entry = Entries[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Position @(index + 1)</h6>
                @if (Entries.Count > 1)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Company Name <span class="text-danger">*</span></label>
                    <input class="form-control" value="@entry.Company"
                           @onchange="e => UpdateEntry(index, entry with { Company = (string?)e.Value ?? "" })" />
                </div>
                <div class="col-md-6">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input class="form-control" value="@entry.Title"
                           @onchange="e => UpdateEntry(index, entry with { Title = (string?)e.Value ?? "" })" />
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-4">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control" value="@(entry.StartDate == default ? "" : entry.StartDate.ToString("yyyy-MM-dd"))"
                           @onchange="e => UpdateEntry(index, entry with { StartDate = DateTime.TryParse((string?)e.Value, out var d) ? d : default })" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control" value="@(entry.EndDate?.ToString("yyyy-MM-dd") ?? "")"
                           disabled="@entry.IsCurrent"
                           @onchange="e => UpdateEntry(index, entry with { EndDate = DateTime.TryParse((string?)e.Value, out var d) ? d : null })" />
                </div>
                <div class="col-md-4 d-flex align-items-end">
                    <div class="form-check mb-2">
                        <input type="checkbox" class="form-check-input" id="current-@index" checked="@entry.IsCurrent"
                               @onchange="e => UpdateEntry(index, entry with { IsCurrent = (bool)(e.Value ?? false), EndDate = (bool)(e.Value ?? false) ? null : entry.EndDate })" />
                        <label class="form-check-label" for="current-@index">Currently working here</label>
                    </div>
                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="2" value="@entry.Description"
                          @onchange="e => UpdateEntry(index, entry with { Description = (string?)e.Value ?? "" })"></textarea>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-primary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

@if (_validationError is not null)
{
    <div class="alert alert-danger">@_validationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter] public EventCallback<List<WorkEntryModel>> EntriesChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? _validationError;

    private void UpdateEntry(int index, WorkEntryModel updated)
    {
        Entries[index] = updated;
        EntriesChanged.InvokeAsync(Entries);
    }

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
        EntriesChanged.InvokeAsync(Entries);
    }

    private void RemoveEntry(int index)
    {
        Entries.RemoveAt(index);
        EntriesChanged.InvokeAsync(Entries);
    }

    private async Task HandleNext()
    {
        _validationError = null;
        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) || entry.StartDate == default)
            {
                _validationError = "Each position must have a company name, job title, and start date.";
                return;
            }
        }
        await OnNext.InvokeAsync();
    }

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }
}

