@namespace sv_a26a23e0998644a6b7638ac048aebd54.Components.JobApplication

<h4 class="mb-3">Review & Submit</h4>

@if (Submitted)
{
    <div class="alert alert-success text-center">
        <h5>Application Submitted Successfully!</h5>
        <p class="mb-0">Your application ID is <strong>@ApplicationId</strong>.</p>
    </div>
}
else
{
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditSection.InvokeAsync(1)'>Edit</button>
        </div>
        <div class="card-body">
            <dl class="row mb-0">
                <dt class="col-sm-3">Full Name</dt><dd class="col-sm-9">@FullName</dd>
                <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@Email</dd>
                <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@Phone</dd>
                <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@Address</dd>
            </dl>
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditSection.InvokeAsync(2)'>Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-2 @(entry != WorkEntries.Last() ? "border-bottom pb-2" : "")">
                    <strong>@entry.Title</strong> at @entry.Company<br />
                    <small class="text-muted">
                        @entry.StartDate.ToString("MMM yyyy") &ndash;
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                    </small>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mt-1 mb-0 small">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditSection.InvokeAsync(3)'>Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship)<br />
                    <small>@r.Email &bull; @r.Phone</small>
                </div>
            }
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-link btn-sm p-0" @onclick='() => OnEditSection.InvokeAsync(4)'>Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;" class="mb-0">@CoverLetter</p>
        </div>
    </div>

    @if (_errorMessage is not null)
    {
        <div class="alert alert-danger">@_errorMessage</div>
    }

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@_submitting">
            @if (_submitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public List<WorkHistoryStep.WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public List<ReferencesStep.ReferenceModel> References { get; set; } = new();
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEditSection { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public Func<Task<int>>? OnSubmit { get; set; }
    [Parameter] public bool Submitted { get; set; }
    [Parameter] public int ApplicationId { get; set; }

    private bool _submitting;
    private string? _errorMessage;

    private async Task HandleSubmit()
    {
        if (OnSubmit is null) return;
        _submitting = true;
        _errorMessage = null;
        try
        {
            await OnSubmit();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _submitting = false;
        }
    }
}

