@page "/apply"
@rendermode InteractiveServer
@using sv_a26a23e0998644a6b7638ac048aebd54.Components.JobApplication
@using sv_a26a23e0998644a6b7638ac048aebd54.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    <StepIndicator CurrentStep="_currentStep" OnNavigateToStep="GoToStep" />

    @switch (_currentStep)
    {
        case 1:
            <PersonalInfoStep @bind-FullName="_fullName"
                              @bind-Email="_email"
                              @bind-Phone="_phone"
                              @bind-Address="_address"
                              ValidateEmail="ApplicationService.ValidateEmailAsync"
                              OnNext="NextStep" />
            break;

        case 2:
            <WorkHistoryStep @bind-Entries="_workEntries"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;

        case 3:
            <ReferencesStep @bind-References="_references"
                            OnNext="NextStep"
                            OnBack="PreviousStep" />
            break;

        case 4:
            <CoverLetterStep @bind-CoverLetter="_coverLetter"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;

        case 5:
            <ReviewStep FullName="_fullName"
                        Email="_email"
                        Phone="_phone"
                        Address="_address"
                        WorkEntries="_workEntries"
                        References="_references"
                        CoverLetter="_coverLetter"
                        OnEditSection="GoToStep"
                        OnBack="PreviousStep"
                        OnSubmit="SubmitApplication"
                        Submitted="_submitted"
                        ApplicationId="_applicationId" />
            break;
    }
</div>

@code {
    private int _currentStep = 1;

    // Step 1 state
    private string _fullName = "";
    private string _email = "";
    private string _phone = "";
    private string _address = "";

    // Step 2 state
    private List<WorkHistoryStep.WorkEntryModel> _workEntries = new() { new() };

    // Step 3 state
    private List<ReferencesStep.ReferenceModel> _references = new() { new(), new() };

    // Step 4 state
    private string _coverLetter = "";

    // Submission state
    private bool _submitted;
    private int _applicationId;

    private void NextStep() => _currentStep++;
    private void PreviousStep() => _currentStep--;
    private void GoToStep(int step) => _currentStep = step;

    private async Task<int> SubmitApplication()
    {
        var application = new JobApplication(
            new PersonalInfo(_fullName, _email, _phone, _address),
            new WorkHistory(_workEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)).ToList()),
            _references.Select(r =>
                new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
            _coverLetter
        );

        _applicationId = await ApplicationService.SubmitApplicationAsync(application);
        _submitted = true;
        return _applicationId;
    }
}

