@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter] public EventCallback<List<WorkEntryModel>> EntriesChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? _validationError;

    private static string FormatDate(DateTime date) => date == default ? "" : date.ToString("yyyy-MM-dd");
    private static string FormatNullableDate(DateTime? date) => date?.ToString("yyyy-MM-dd") ?? "";
    private static string Str(object? value) => (string?)value ?? "";

    private void SetCompany(int index, ChangeEventArgs e)
    {
        Entries[index].Company = Str(e.Value);
        EntriesChanged.InvokeAsync(Entries);
    }

    private void SetTitle(int index, ChangeEventArgs e)
    {
        Entries[index].Title = Str(e.Value);
        EntriesChanged.InvokeAsync(Entries);
    }

    private void SetStartDate(int index, ChangeEventArgs e)
    {
        Entries[index].StartDate = DateTime.TryParse(Str(e.Value), out var d) ? d : default;
        EntriesChanged.InvokeAsync(Entries);
    }

    private void SetEndDate(int index, ChangeEventArgs e)
    {
        Entries[index].EndDate = DateTime.TryParse(Str(e.Value), out var d) ? d : null;
        EntriesChanged.InvokeAsync(Entries);
    }

    private void SetIsCurrent(int index, ChangeEventArgs e)
    {
        var isCurrent = (bool)(e.Value ?? false);
        Entries[index].IsCurrent = isCurrent;
        if (isCurrent) Entries[index].EndDate = null;
        EntriesChanged.InvokeAsync(Entries);
    }

    private void SetDescription(int index, ChangeEventArgs e)
    {
        Entries[index].Description = Str(e.Value);
        EntriesChanged.InvokeAsync(Entries);
    }

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
        EntriesChanged.InvokeAsync(Entries);
    }

    private void RemoveEntry(int index)
    {
        Entries.RemoveAt(index);
        EntriesChanged.InvokeAsync(Entries);
    }

    private async Task HandleNext()
    {
        _validationError = null;
        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) || entry.StartDate == default)
            {
                _validationError = "Each position must have a company name, job title, and start date.";
                return;
            }
        }
        await OnNext.InvokeAsync();
    }

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }
}

